content.text:
{
  "核心的メッセージ": "組織課題の多くは人と集団の相互作用という「プロセス」に根差す。コンサルタントの本質的役割は、謙虚な問いかけと共同診断を通じて、クライアントが自らプロセスを観察・理解・調整できる能力を高めることである。",
  "エグゼクティブ・サマリー（「要約=問い×答え×根拠（Why＝なぜそうなのか？&How=そのためには？）」の形式で、そこさえ見れば本を読まずとも理解できるようにまとめる）": "問い: なぜ外部の知見や施策があっても組織の改善が持続しないのか？／答え: 真因は「人と集団のやり取り＝プロセス」にあり、解決はクライアント自身のプロセス認知・調整力の強化によってのみ定着する。／Why: 画一的処方は状況固有の相互作用を捉えきれず依存を生みがち。一方、現実接触・共同診断・最小十分介入という原則は内省と学習を駆動し、自走を促す。／How: 謙虚な問いかけで信頼を築き、エントリーと契約→観察と共同診断→フィードバック→小さな実験的介入→振り返りの学習サイクルを回す。介入の深さとタイミングを調整し、問題と解の所有権を常にクライアントへ戻す。",
  "主要概念の説明（各概念を1〜2文で定義。可能なら一言要約も）": [
    {
      "概念": "プロセス・コンサルテーション",
      "定義": "内容の専門解ではなく、相互作用の質を高める支援によって、クライアントの自己診断・自己修正力を伸ばすアプローチ。",
      "一言要約": "プロセスを助ける"
    },
    {
      "概念": "助ける関係",
      "定義": "対等性と信頼に基づき、双方が学ぶ前提で築く協働関係。依存を作らず自律を育てる。",
      "一言要約": "対等な協働"
    },
    {
      "概念": "謙虚な問いかけ",
      "定義": "相手が主役であることを尊重し、先入観を抑えて真のデータを引き出す質問姿勢。",
      "一言要約": "先に問う謙虚さ"
    },
    {
      "概念": "ここ・いま志向",
      "定義": "現在進行中のやり取りや感情に注目し、その場で小さく検証・調整する実践視点。",
      "一言要約": "現場直視"
    },
    {
      "概念": "共同診断",
      "定義": "観察・意味づけ・仮説形成をクライアントと共に行い、理解の所有権を共有する営み。",
      "一言要約": "一緒に理解する"
    },
    {
      "概念": "契約とエントリー",
      "定義": "支援の目的・範囲・役割・期待・境界を明確化して合意し、介入の土台を整える。",
      "一言要約": "土台づくり"
    },
    {
      "概念": "所有権（問題と解）",
      "定義": "問題認識と解決策の責任主体はクライアントにあるという原則。定着度を左右する。",
      "一言要約": "自分ごと化"
    },
    {
      "概念": "介入の深さとタイミング",
      "定義": "表層の手順から関係・感情・前提に至るまで、影響レベルと投入時機を選ぶ設計。",
      "一言要約": "どこまで・いつ"
    },
    {
      "概念": "最小十分介入",
      "定義": "必要最小限で最大効果を狙い、過剰介入や依存化を避ける原則。",
      "一言要約": "小さく効かす"
    },
    {
      "概念": "三つのコンサルモデル",
      "定義": "専門家モデル／医者‐患者モデル／プロセス・コンサルモデルの役割枠組みと適用条件。",
      "一言要約": "役割の選択"
    },
    {
      "概念": "心理的安全性",
      "定義": "不利益なく本音や仮説を出せる感覚。質の高いデータ収集の前提となる。",
      "一言要約": "本音の土壌"
    },
    {
      "概念": "フィードバックと学習ループ",
      "定義": "観察→可視化→合意→試行→振り返りの循環で、組織能力を内製化する。",
      "一言要約": "回して定着"
    }
  ],
  "概念間の関係性や因果関係（箇条書きや簡易図式テキストで可）": [
    "謙虚な問いかけ → 心理的安全性 → 本音データ → 共同診断の質向上",
    "明確な契約 → 役割境界の安定 → 介入の受容度向上",
    "最小十分介入 × 適切なタイミング → 依存低下・自律性向上",
    "ここ・いま志向 → 生きたプロセス観察 → 即時の小実験",
    "所有権の保持 → 実行コミットメント → 施策の定着",
    "フィードバック → 学習ループ → 能力の内製化",
    "モデル選択（専門家/医者‐患者/PC） ↔ 課題の性質・成熟度・緊急度"
  ],
  "構造と論理展開（章構成の要点や議論の流れを説明）": [
    "問題提起: 組織の成果を左右するのは“内容”より“プロセス”であるという視座転換。",
    "モデル比較: 専門家・医者‐患者・プロセス・コンサルの役割と限界を整理。",
    "助ける関係: 対等性、現実接触、信頼形成の要件と態度（謙虚な問い）。",
    "エントリーと契約: 目的・範囲・役割・境界・成功基準・倫理の合意設計。",
    "データ収集: 観察・面談・会議参加を通じた“ここ・いま”のプロセス把握。",
    "共同診断とフィードバック: 可視化と意味づけ、合意形成の技法。",
    "介入設計: 深さとタイミングの調整、会議運営・コミュニケーション・役割/規範への働きかけ。",
    "原則と倫理: 常に役に立つこと、現実接触、無知の活用、行為は全て介入、所有権の維持等の原則。",
    "能力移転と終了: 自走化の確認、フォローアップ、依存を残さないクロージング。"
  ],
  "重要な引用（原文/要旨＋なぜ重要か1文で）": [
    {
      "要旨": "コンサルタントの役目は、クライアントの自己診断力を高めることだ。",
      "なぜ重要か": "解の提供ではなく能力移転が目的であると明確に示すため。"
    },
    {
      "要旨": "あなたが行うことは全て介入であり、関係に影響する。",
      "なぜ重要か": "無意識の振る舞いも関係を形作ると自覚させ、慎重さを促す。"
    },
    {
      "要旨": "“ここ・いま”の相互作用に注目せよ。",
      "なぜ重要か": "抽象論より実際のやり取りが変化のレバーになるから。"
    },
    {
      "要旨": "問題と解の所有権はクライアントにある。",
      "なぜ重要か": "依存を避け、自走と定着を生む設計原則になるため。"
    }
  ],
  "今日できるアクション（読後すぐに15〜30分で実行できるもの）": [
    "描く:利害関係者マップ15分",
    "観察し記録する:会議の発言15分",
    "合意する:次の1on1目的と契約15分"
  ],
  "関連書籍（各要素は { \"書名\": \"...\", \"著者\": \"...\", \"関連性\": \"なぜ関連するか\" } の配列）": [
    {
      "書名": "プロセス・コンサルテーション再考",
      "著者": "エドガー・H・シャイン",
      "関連性": "PCの原則を再整理し、10原則と事例で深化させる続編。"
    },
    {
      "書名": "謙虚に問いかける",
      "著者": "エドガー・H・シャイン",
      "関連性": "PCの中核スキルである“謙虚な問い”を具体的に解説。"
    },
    {
      "書名": "人を助けるということ",
      "著者": "エドガー・H・シャイン",
      "関連性": "助ける関係の心理と倫理を広く扱いPCの基盤を補完。"
    },
    {
      "書名": "学習する組織",
      "著者": "ピーター・M・センゲ",
      "関連性": "学習ループとシステム思考がPCの自走化と相補的。"
    },
    {
      "書名": "組織文化とリーダーシップ",
      "著者": "エドガー・H・シャイン",
      "関連性": "前提や規範への働きかけなど介入の深さ理解に資する。"
    },
    {
      "書名": "クリティカル・コンバーセーションズ",
      "著者": "ケリー・パターソンほか",
      "関連性": "高リスク対話の技法がプロセス改善の実践に直結。"
    }
  ]
}
